/* ── The close checklist (Finance model spec §8.6, §5 status tiers) ──
   `blocker` items are resolvable — clicking the action marks them done,
   decrementing the "N left" count. `done` items are state only. The round
   status tick (green ✓ / amber !) is STATE, never a checkbox. */
export type ChecklistKind = "blocker" | "done";

export interface ChecklistItem {
  key: string;
  /** "blocker" shows an amber ! tick + an action button; "done" shows a green ✓. */
  kind: ChecklistKind;
  label: string;
  /** Sub-line shown while the item is unresolved. */
  sub: string;
  /** Sub-line shown after a blocker is resolved in demo state. */
  resolvedSub?: string;
  /** Action button label for blockers (e.g. "Classify →"). */
  actionLabel?: string;
  /** Resting button label for done items (e.g. "Done" / "Ready"). */
  doneLabel?: string;
}

