/* ── Accountant handoff hero (Finance model spec §7) ── */

/** Receipt-custody state for a preview transaction. */
export type ReceiptState = "attached" | "auto" | "missing";

export interface PreviewTransaction {
  date: string;
  payee: string;
  /** Signed amount string, USD, already formatted (tabular). */
  amount: string;
  category: string;
  /** The operational context link an accountant would otherwise have to ask for. */
  context: string;
  /** VAT treatment — computed amount, or "—" when not applicable. */
  vat: string;
  receipt: ReceiptState;
}

