/** Export formats — each reshapes the preview's column-header vocabulary to
    the destination tool. The first 5 headers map to the preview's 6 columns;
    the 7th column ("Receipt"/"Attachment"/etc.) is the custody column. */
export interface ExportFormat {
  key: string;
  label: string;
  file: string;
  /** Column headers in the destination tool's vocabulary (7 columns). */
  cols: [string, string, string, string, string, string, string];
}

