/** Delivery method — note + button copy are reshaped by the active format. */
export interface DeliveryMethod {
  key: string;
  label: string;
  /** Foot-note copy; {label} is replaced with the active format's label. */
  note: (formatLabel: string) => string;
  /** Primary button copy; {label} is replaced with the active format's label. */
  button: (formatLabel: string) => string;
  /** Confirmation copy after the (demo) action; {file} replaced for downloads. */
  done: (file: string) => string;
}

