/* ── Verdict factors (the consequence-read alongside the verdict block) ── */
export interface VerdictFactor {
  key: string;
  /** "bad" while the matching blocker is open; "ok" once resolved. */
  tone: "ok" | "bad" | "warn";
  label: string;
  openValue: string;
  resolvedValue: string;
  /** If set, this factor flips ok once the named blocker is resolved. */
  blockerKey?: string;
}

